index 394dfca262e1..bb6aee5e72b7 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3090,6 +3090,68 @@ static Instruction *foldNestedSelects(SelectInst &OuterSelVal,
                             !IsAndVariant ? SelInner : InnerSel.FalseVal);
 }

+/// Fold select(c2, select(c1, A, B), select(c1, B, A)) -> select(xor(c1, c2), B, A)
+/// This recognizes when two inner selects have the same condition but swapped operands.
+/// Also handles commuted form: select(c2, select(c1, B, A), select(c1, A, B))
+static Instruction *foldSymmetricSelects(SelectInst &SI,
+                                         InstCombiner::BuilderTy &Builder) {
+  Value *CondVal = SI.getCondition();
+  Value *TrueVal = SI.getTrueValue();
+  Value *FalseVal = SI.getFalseValue();
+
+  // Both true and false values must be selects.
+  auto *TrueSI = dyn_cast<SelectInst>(TrueVal);
+  auto *FalseSI = dyn_cast<SelectInst>(FalseVal);
+  if (!TrueSI || !FalseSI)
+    return nullptr;
+
+  // The inner selects must have the same condition.
+  if (TrueSI->getCondition() != FalseSI->getCondition())
+    return nullptr;
+
+  Value *InnerCond = TrueSI->getCondition();
+  
+  // The condition types must match for xor to work.
+  if (InnerCond->getType() != CondVal->getType())
+    return nullptr;
+
+  Value *TrueA = TrueSI->getTrueValue();
+  Value *TrueB = TrueSI->getFalseValue();
+  Value *FalseA = FalseSI->getTrueValue();
+  Value *FalseB = FalseSI->getFalseValue();
+
+  // Check if operands are swapped: True(A,B) and False(B,A)
+  // Or commuted: True(B,A) and False(A,B)
+  bool NormalForm = (TrueA == FalseB && TrueB == FalseA);
+  bool CommutedForm = (TrueA == FalseA && TrueB == FalseB);
+  
+  if (!NormalForm && !CommutedForm)
+    return nullptr;
+
+  // Profitability: only fold if it reduces instruction count.
+  // We're replacing 3 selects with 1 xor + 1 select.
+  // This requires both inner selects to have a single use,
+  // because we need to eliminate both of them.
+  bool TrueSIHasOneUse = TrueSI->hasOneUse();
+  bool FalseSIHasOneUse = FalseSI->hasOneUse();
+
+  // Both inner selects must have a single use for this to be profitable.
+  if (!TrueSIHasOneUse || !FalseSIHasOneUse)
+    return nullptr;
+
+
+  // Create: xor = xor c1, c2
+  Value *Xor = Builder.CreateXor(InnerCond, CondVal);
+
+  // Create: select xor, B, A (note: B is TrueB, A is TrueA for normal form)
+  // For commuted form, select xor, A, B
+  Value *SelTrue = NormalForm ? TrueB : TrueA;
+  Value *SelFalse = NormalForm ? TrueA : TrueB;
+  SelectInst *NewSel = SelectInst::Create(Xor, SelTrue, SelFalse);
+  NewSel->takeName(&SI);
+  return NewSel;
+}
+
 Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
   Value *CondVal = SI.getCondition();
   Value *TrueVal = SI.getTrueValue();
@@ -3990,6 +4052,9 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   if (Instruction *I = foldNestedSelects(SI, Builder))
     return I;

+  if (Instruction *I = foldSymmetricSelects(SI, Builder))
+    return I;
+
   // Match logical variants of the pattern,
   // and transform them iff that gets rid of inversions.
   //   (~x) | y  -->  ~(x & (~y))

