/// Fold select(c2, select(c1, A, B), select(c1, B, A)) -> select(xor(c1, c2), B, A)
/// This recognizes when two inner selects have the same condition but swapped operands.
static Instruction *foldSymmetricSelects(SelectInst &SI,
                                         InstCombiner::BuilderTy &Builder) {
  Value *CondVal = SI.getCondition();
  Value *TrueVal = SI.getTrueValue();
  Value *FalseVal = SI.getFalseValue();

  // Both true and false values must be selects.
  auto *TrueSI = dyn_cast<SelectInst>(TrueVal);
  auto *FalseSI = dyn_cast<SelectInst>(FalseVal);
  if (!TrueSI || !FalseSI)
    return nullptr;

  // The inner selects must have the same condition.
  if (TrueSI->getCondition() != FalseSI->getCondition())
    return nullptr;

  // The inner selects must have swapped operands:
  // TrueSI: select c1, A, B
  // FalseSI: select c1, B, A
  Value *InnerCond = TrueSI->getCondition();
  Value *TrueA = TrueSI->getTrueValue();
  Value *TrueB = TrueSI->getFalseValue();
  Value *FalseA = FalseSI->getTrueValue();
  Value *FalseB = FalseSI->getFalseValue();

  // Check if operands are swapped: True(A,B) and False(B,A)
  if (TrueA != FalseB || TrueB != FalseA)
    return nullptr;

  // Profitability: only fold if it reduces instruction count.
  // We're replacing 3 selects with 1 xor + 1 select.
  // This is profitable if the outer select's condition has one use,
  // or if one of the inner selects has one use.
  bool CondHasOneUse = CondVal->hasOneUse();
  bool TrueSIHasOneUse = TrueSI->hasOneUse();
  bool FalseSIHasOneUse = FalseSI->hasOneUse();

  // We need at least one of the conditions/selects to have a single use
  // to avoid increasing instruction count.
  if (!CondHasOneUse && !TrueSIHasOneUse && !FalseSIHasOneUse)
    return nullptr;

  // Create: xor = xor c1, c2
  Value *Xor = Builder.CreateXor(InnerCond, CondVal);

  // Create: select xor, B, A (note: B is TrueB, A is TrueA)
  SelectInst *NewSel = SelectInst::Create(Xor, TrueB, TrueA);
  NewSel->takeName(&SI);
  return NewSel;
}

